import{_ as a,v as t,f as o,i as r}from"./chunks/framework.jfF5glnW.js";const _=JSON.parse('{"title":"Week 6 | ESP32 嵌入式入门","description":"","frontmatter":{"title":"Week 6 | ESP32 嵌入式入门","date":"2026-04-07T00:00:00.000Z","tags":["课程周志","ESP32","嵌入式"],"cover":"/code2real_blog/posts/week6/xiucai.jpg"},"headers":[],"relativePath":"posts/week6.md","filePath":"posts/week6.md"}'),p={name:"posts/week6.md"};function s(i,e,l,c,d,n){return t(),o("div",null,[...e[0]||(e[0]=[r('<p>第六周开始进入 ESP32 嵌入式开发。本周主要熟悉开发板连接、程序上传、GPIO 控制和串口调试。</p><hr><img src="/code2real_blog/posts/week6/xiucai.jpg" alt="Week 6 image"><h2 id="本周学习内容" tabindex="-1">本周学习内容 <a class="header-anchor" href="#本周学习内容" aria-label="Permalink to &quot;本周学习内容&quot;">​</a></h2><p>本周的学习对象从建模和制作转向嵌入式程序。ESP32 的特点是代码会直接影响硬件状态，因此调试时不能只看程序是否编译通过，还要看板子、引脚和外设是否配合正确。</p><p>课程中主要学习了开发环境配置、板型选择、端口识别、程序上传、串口监视器使用，以及 <code>setup()</code> 和 <code>loop()</code> 的基本结构。代码部分练习了变量、条件判断、循环、函数调用和 GPIO 输出控制。</p><h2 id="实践过程" tabindex="-1">实践过程 <a class="header-anchor" href="#实践过程" aria-label="Permalink to &quot;实践过程&quot;">​</a></h2><p>实践从最基础的流程开始：连接开发板，选择正确端口，上传示例程序，再通过串口观察运行信息。随后尝试控制 LED 状态，修改延时时间，切换不同引脚输出，逐步熟悉 ESP32 的执行节奏。</p><p>这些练习规模不大，但帮助我建立了一个基本对应关系：代码中的引脚编号要对应实际接线，程序中的状态变化要能在硬件上观察到，串口输出则用来确认程序是否按预期执行。</p><h2 id="遇到的问题" tabindex="-1">遇到的问题 <a class="header-anchor" href="#遇到的问题" aria-label="Permalink to &quot;遇到的问题&quot;">​</a></h2><p>本周的问题主要来自软硬件同时存在变量。程序可以成功上传，并不代表功能一定正确。端口选错、板型不匹配、波特率不一致、引脚编号理解错误，都会导致结果和预期不一致。</p><p>另一个困难是排查顺序。以前写普通程序时，问题大多集中在代码逻辑；现在还要检查接线、供电、外设状态和开发板配置。信息量一下变多，排错需要更有耐心，也更需要记录每一次修改。</p><h2 id="本周收获" tabindex="-1">本周收获 <a class="header-anchor" href="#本周收获" aria-label="Permalink to &quot;本周收获&quot;">​</a></h2><p>通过本周练习，我初步掌握了 ESP32 的基本开发流程，也理解了嵌入式开发和普通软件编写的区别。这里的程序不是只在屏幕里运行，而是要和真实硬件产生对应关系。</p><p>本周虽然还没有完成完整作品，但基础流程已经跑通。能稳定完成上传、串口查看和简单 GPIO 控制，后续才有条件继续接入传感器、舵机和网络功能。</p><hr>',16)])])}const P=a(p,[["render",s]]);export{_ as __pageData,P as default};
